'use client';
import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import AppLayout from '@/components/AppLayout';
import { Save, FileText, Check, LayoutTemplate } from 'lucide-react';
import { useStore, useActiveCompany } from '@/lib/store';
import { InvoicePrintTemplate } from '@/components/InvoicePrintTemplate';

const mockInvoice = {
    invoiceNumber: "INV-DEMO-001",
    date: new Date().toISOString().slice(0, 10),
    partyName: "Valued Customer",
    partyPhone: "9876543210",
    grandTotal: 1250.00,
    subTotal: 1100.00,
    totalDiscount: 50.00,
    totalGst: 200.00,
    roundOff: 0,
    items: [
        { name: "Premium Quality Basmati Rice", qty: 2, unit: "Kg", rate: 500, amount: 1000, hsnCode: "1006", discountAmt: 50, totalGst: 180 },
        { name: "Organic Honey 500g", qty: 1, unit: "Box", rate: 100, amount: 100, hsnCode: "0409", discountAmt: 0, totalGst: 20 },
    ]
};
const THEMES = [
    { id: 'classic', label: 'Classic' },
    { id: 'creative', label: 'Creative (Pinterest)' },
    { id: 'modern', label: 'Modern Edge' },
    { id: 'waves', label: 'Smooth Waves' },
    { id: 'minimalist', label: 'Minimal Clean' },
    { id: 'bold_orange', label: 'Bold Retail' },
    { id: 'luxe_gold', label: 'Luxe Gold' },
    { id: 'vibrant', label: 'Vibrant Blue' },
    { id: 'retro', label: 'Retro Typewriter' },
    { id: 'quick_bill', label: 'Quick POS Thermal' },
    { id: 'beige_dark', label: 'Beige & Dark' },
    { id: 'sea_green', label: 'Sea Green' },
    { id: 'formal_quote', label: 'Formal Quote' },
];

export default function TemplateSettingsPage() {
    const router = useRouter();
    const company = useActiveCompany();
    const { updateCompany } = useStore();

    const [theme, setTheme] = useState('classic');
    const [columns, setColumns] = useState({
        sn: true,
        hsn: true,
        rate: true,
        discount: true,
        tax: true,
    });

    useEffect(() => {
        if (company) {
            setTheme(company.templateTheme || 'classic');
            if (company.templateColumns) {
                setColumns(company.templateColumns);
            }
        }
    }, [company]);

    const handleSave = () => {
        if (!company) return;
        updateCompany(company.id, {
            templateTheme: theme,
            templateColumns: columns,
        });
        alert('Invoice template settings saved successfully.');
        router.push('/company/settings');
    };

    if (!company) return null;

    return (
        <AppLayout title="Invoice Templates">
            <div style={{ maxWidth: 1200, margin: '0 auto', display: 'flex', flexDirection: 'column', gap: 24 }}>

                {/* Header Section */}
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: 16 }}>
                    <div>
                        <h1 style={{ fontSize: 28, fontWeight: 900, color: '#1A1A2E', letterSpacing: '-0.02em', margin: 0 }}>Invoice Templates</h1>
                        <p style={{ fontSize: 14, color: '#718096', marginTop: 4 }}>Customize how your bills appear to your customers.</p>
                    </div>
                    <button onClick={handleSave} className="btn btn-green" style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '12px 24px', fontSize: 14, boxShadow: '0 4px 16px rgba(52,168,83,0.3)' }}>
                        <Save size={18} /> Save Active Template
                    </button>
                </div>

                <div className="template-grid">
                    {/* Settings Column */}
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
                        {/* Themes Selection */}
                        <div className="card" style={{ padding: '24px' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 20 }}>
                                <div style={{ width: 40, height: 40, borderRadius: 12, background: 'linear-gradient(135deg, #E8F0FE, #D2E3FC)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                    <LayoutTemplate size={20} color="#1967D2" />
                                </div>
                                <div>
                                    <h2 style={{ fontSize: 18, fontWeight: 800, color: '#1A202C', margin: 0 }}>Design Theme</h2>
                                    <p style={{ fontSize: 12, color: '#718096', margin: '2px 0 0' }}>Select the primary blueprint</p>
                                </div>
                            </div>

                            <div className="theme-selector-grid">
                                {THEMES.map(t => {
                                    const active = theme === t.id;
                                    return (
                                        <div key={t.id} onClick={() => setTheme(t.id)} style={{ padding: 16, borderRadius: 14, border: '2px solid', borderColor: active ? '#4285F4' : '#E2E8F0', background: active ? '#F8FAFC' : 'white', cursor: 'pointer', display: 'flex', flexDirection: 'column', gap: 12, transition: 'all 0.2s cubic-bezier(0.4, 0, 0.2, 1)', boxShadow: active ? '0 8px 24px rgba(66, 133, 244, 0.12)' : 'none', transform: active ? 'translateY(-2px)' : 'none' }}>
                                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                                <div style={{ width: 48, height: 48, borderRadius: 10, background: ['#4285F4', '#34A853', '#EA4335', '#FBBC04', '#9333EA', '#1A1A2E'][THEMES.indexOf(t) % 6] + '15', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                                    <FileText size={22} color={['#4285F4', '#34A853', '#EA4335', '#FBBC04', '#9333EA', '#1A1A2E'][THEMES.indexOf(t) % 6]} />
                                                </div>
                                                <div style={{ width: 22, height: 22, borderRadius: '50%', border: '2px solid', borderColor: active ? '#4285F4' : '#CBD5E0', display: 'flex', alignItems: 'center', justifyContent: 'center', background: active ? '#4285F4' : 'transparent', transition: 'all 0.2s' }}>
                                                    {active && <Check size={12} color="white" />}
                                                </div>
                                            </div>
                                            <span style={{ fontWeight: 800, fontSize: 14, color: active ? '#1967D2' : '#4A5568' }}>{t.label}</span>
                                        </div>
                                    )
                                })}
                            </div>
                        </div>

                        {/* Columns Selection */}
                        <div className="card" style={{ padding: '24px' }}>
                            <h3 style={{ fontSize: 14, fontWeight: 800, color: '#1A202C', textTransform: 'uppercase', marginBottom: 6, letterSpacing: '0.05em' }}>Visible Columns</h3>
                            <p style={{ fontSize: 13, color: '#718096', marginBottom: 20 }}>Toggle columns visible on the final print output.</p>

                            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 12 }}>
                                {Object.keys(columns).map((key) => {
                                    const isActive = columns[key as keyof typeof columns];
                                    return (
                                        <div key={key} onClick={() => setColumns({ ...columns, [key as keyof typeof columns]: !isActive })} style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '10px 16px', background: isActive ? '#E8F0FE' : '#F8FAFC', borderRadius: 99, cursor: 'pointer', border: '1.5px solid', borderColor: isActive ? '#4285F4' : '#E2E8F0', transition: 'all 0.2s', userSelect: 'none' }}>
                                            <div style={{ width: 16, height: 16, borderRadius: 4, background: isActive ? '#4285F4' : 'transparent', border: isActive ? 'none' : '2px solid #CBD5E0', display: 'flex', alignItems: 'center', justifyContent: 'center', transition: 'all 0.2s' }}>
                                                {isActive && <Check size={12} color="white" />}
                                            </div>
                                            <span style={{ fontWeight: 700, fontSize: 12, textTransform: 'uppercase', color: isActive ? '#1967D2' : '#718096' }}>{key}</span>
                                        </div>
                                    )
                                })}
                            </div>
                        </div>
                    </div> {/* End settings col */}

                    {/* Preview Column (Sticky on Desktop) */}
                    <div className="preview-container">
                        <div className="card" style={{ padding: '24px', background: 'linear-gradient(180deg, #F8FAFC 0%, #F1F5F9 100%)', display: 'flex', flexDirection: 'column', alignItems: 'center', height: '100%', position: 'relative', overflow: 'hidden' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 24, zIndex: 2 }}>
                                <div style={{ width: 8, height: 8, borderRadius: '50%', background: '#34A853', boxShadow: '0 0 12px #34A853' }} />
                                <span style={{ fontSize: 13, fontWeight: 800, color: '#4A5568', textTransform: 'uppercase', letterSpacing: '0.1em' }}>Live Engine Render</span>
                            </div>

                            <div style={{
                                width: '100%',
                                aspectRatio: '210/297',
                                background: 'white',
                                boxShadow: '0 20px 40px rgba(0,0,0,0.08), 0 1px 3px rgba(0,0,0,0.05)',
                                borderRadius: 4,
                                position: 'relative',
                                overflow: 'hidden',
                                zIndex: 2
                            }}>
                                <div className="preview-scale" style={{
                                    position: 'absolute', top: 0, left: 0,
                                    width: '210mm', minHeight: '297mm',
                                    transformOrigin: 'top left',
                                    pointerEvents: 'none'
                                }}>
                                    <InvoicePrintTemplate
                                        invoice={mockInvoice}
                                        company={{ ...company, templateTheme: theme, templateColumns: columns }}
                                        copies={1}
                                        previewMode={true}
                                    />
                                </div>
                            </div>

                            {/* Decorative Background Elements */}
                            <div style={{ position: 'absolute', top: -50, right: -50, width: 200, height: 200, background: '#4285F4', borderRadius: '50%', filter: 'blur(80px)', opacity: 0.1, zIndex: 1 }} />
                            <div style={{ position: 'absolute', bottom: -50, left: -50, width: 200, height: 200, background: '#34A853', borderRadius: '50%', filter: 'blur(80px)', opacity: 0.1, zIndex: 1 }} />
                        </div>
                    </div>
                </div>
            </div>

            <style>{`
                .template-grid { display: flex; flex-direction: column; gap: 24px; }
                .theme-selector-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(160px, 1fr)); gap: 16px; }
                .preview-scale { transform: scale(0.35); }
                .preview-container { margin-top: 10px; }
                
                @media (min-width: 640px) { 
                    .preview-scale { transform: scale(0.40); } 
                }
                @media (min-width: 1024px) { 
                    .template-grid { display: grid; grid-template-columns: 1fr 450px; gap: 40px; }
                    .preview-container { position: sticky; top: 80px; height: calc(100vh - 120px); }
                    .theme-selector-grid { grid-template-columns: repeat(2, 1fr); padding-right: 10px; }
                    .preview-scale { transform: scale(0.45); } 
                }
                @media (min-width: 1280px) { 
                    .preview-scale { transform: scale(0.48); } 
                }
            `}</style>
        </AppLayout>
    );
}
